#!/usr/bin/perl

use strict;
use warnings;
use CGI;

my $cgi = CGI->new;
print $cgi->header('text/html');

my $log_dir = '/path/to/log/directory'; 
my $filename = $cgi->param('logfile');

if ($filename) {
    my $filepath = "$log_dir/$filename";

    if (-e $filepath && -r $filepath) {
        open(my $fh, '<', $filepath) or die "Cannot open file: $!";
        print $cgi->start_html('Log Viewer');
        print $cgi->h1("Log File: $filename");
        print $cgi->pre(join("", <$fh>));
        close($fh);
        print $cgi->end_html;
    } else {
        print $cgi->start_html('Error');
        print $cgi->h1("Error: File not found or not readable.");
        print $cgi->end_html;
    }
} else {
    print $cgi->start_html('Error');
    print $cgi->h1("Error: No log file specified.");
    print $cgi->end_html;
}